(()=>{const o=window.fetch,p=XMLHttpRequest.prototype,r=p.setRequestHeader;let c=!1;const h=async t=>{if(c)return;c=!0;window.fetch=o;p.setRequestHeader=r;try{await navigator.clipboard.writeText(t);console.log('%c✅ 토큰 클립보드 복사 ('+t.length+'자)','color:#0a0;font-weight:bold');console.log('preview:',t.slice(0,20)+'...'+t.slice(-10))}catch(e){console.warn('클립보드 실패. 직접 복사:',t)}};window.fetch=function(u,i={}){if(i&&i.headers)try{const a=new Headers(i.headers).get('authorization');if(a&&/^Bearer eyJ/i.test(a))h(a.replace(/^Bearer\s+/i,''))}catch(e){}return o.apply(this,arguments)};p.setRequestHeader=function(n,v){if(/^authorization$/i.test(n)&&/^Bearer eyJ/i.test(String(v)))h(String(v).replace(/^Bearer\s+/i,''));return r.apply(this,arguments)};console.log('%c🎣 활성화 - 페이지를 클릭하거나 새로고침하세요','color:#08f;font-weight:bold')})();
